        public static float GetNoise(float x, float y)
        {
            // Unity's Perlin noise has a period of 256 units
            // Wrap coordinates to stay within our sampled range
            const float PERLIN_PERIOD = 256f;
            x = x % PERLIN_PERIOD;
            y = y % PERLIN_PERIOD;
            
            // Handle negative wrapping
            if (x < 0) x += PERLIN_PERIOD;
            if (y < 0) y += PERLIN_PERIOD;
            
            // Round to nearest 1.0 for lookup (1-unit resolution)
            float rx = (float)Math.Round(x, 0);
            float ry = (float)Math.Round(y, 0);
            
            if (Samples.TryGetValue((rx, ry), out float value))
            {
                return value;
            }
            
            // Fallback: bilinear interpolation for sub-grid queries
            float x0 = (float)Math.Floor(x);
            float x1 = x0 + 1f;
            float y0 = (float)Math.Floor(y);
            float y1 = y0 + 1f;
            
            float fx = x - x0;
            float fy = y - y0;
            
            if (Samples.TryGetValue((x0, y0), out float v00) &&
                Samples.TryGetValue((x1, y0), out float v10) &&
                Samples.TryGetValue((x0, y1), out float v01) &&
                Samples.TryGetValue((x1, y1), out float v11))
            {
                // Bilinear interpolation
                float v0 = v00 * (1 - fx) + v10 * fx;
                float v1 = v01 * (1 - fx) + v11 * fx;
                return v0 * (1 - fy) + v1 * fy;
            }
            
            throw new ArgumentException($"Coordinate ({x}, {y}) not in lookup table after wrapping");
        }
    }
